"use client"

import * as React from "react"
import { CheckIcon } from "lucide-react"

import { cn } from "@/lib/utils"

// ─── Types ────────────────────────────────────────────────────────────────────

type StepState = "active" | "completed" | "upcoming"
type StepperOrientation = "horizontal" | "vertical"

// ─── Stepper Context ──────────────────────────────────────────────────────────

interface StepperContextValue {
  value: string
  onValueChange: (value: string) => void
  orientation: StepperOrientation
}

const StepperContext = React.createContext<StepperContextValue | null>(null)

function useStepper() {
  const context = React.useContext(StepperContext)
  if (!context) {
    throw new Error("useStepper must be used within a <Stepper>")
  }
  return context
}

// ─── StepperItem Context ──────────────────────────────────────────────────────

interface StepperItemContextValue {
  value: string
  state: StepState
  disabled: boolean
}

const StepperItemContext = React.createContext<StepperItemContextValue | null>(
  null
)

function useStepperItem() {
  const context = React.useContext(StepperItemContext)
  if (!context) {
    throw new Error("useStepperItem must be used within a <StepperItem>")
  }
  return context
}

// ─── Stepper ──────────────────────────────────────────────────────────────────

interface StepperProps extends React.ComponentProps<"div"> {
  /** The controlled active step value. */
  value?: string
  /** The default active step value for uncontrolled usage. */
  defaultValue?: string
  /** Callback fired when the active step changes. */
  onValueChange?: (value: string) => void
  /** Visual layout direction. @default "horizontal" */
  orientation?: StepperOrientation
}

function Stepper({
  value: valueProp,
  defaultValue = "",
  onValueChange,
  orientation = "horizontal",
  className,
  ...props
}: StepperProps) {
  const [internalValue, setInternalValue] = React.useState(defaultValue)
  const isControlled = valueProp !== undefined
  const value = isControlled ? valueProp : internalValue

  const handleValueChange = React.useCallback(
    (newValue: string) => {
      if (!isControlled) {
        setInternalValue(newValue)
      }
      onValueChange?.(newValue)
    },
    [isControlled, onValueChange]
  )

  return (
    <StepperContext.Provider
      value={{ value, onValueChange: handleValueChange, orientation }}
    >
      <div
        data-slot="stepper"
        data-orientation={orientation}
        className={cn("flex flex-col", className)}
        {...props}
      />
    </StepperContext.Provider>
  )
}

// ─── StepperList ──────────────────────────────────────────────────────────────

/**
 * Container that arranges StepperItem and StepperSeparator children in a row
 * (horizontal) or column (vertical). Nest your items and separators inside
 * this component.
 */
function StepperList({ className, ...props }: React.ComponentProps<"div">) {
  const { orientation } = useStepper()
  return (
    <div
      data-slot="stepper-list"
      data-orientation={orientation}
      className={cn(
        "flex",
        orientation === "horizontal" ? "flex-row items-start" : "flex-col",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperItem ──────────────────────────────────────────────────────────────

interface StepperItemProps extends React.ComponentProps<"div"> {
  /** Unique identifier for this step. Matched against the Stepper value. */
  value: string
  /**
   * Mark this step as completed. Used to show a check indicator when the step
   * is not active. Typically set to `true` for all steps before the current
   * active step.
   */
  completed?: boolean
  /** Prevent the user from clicking this step's trigger. */
  disabled?: boolean
}

function StepperItem({
  value,
  completed = false,
  disabled = false,
  className,
  ...props
}: StepperItemProps) {
  const { value: activeValue, orientation } = useStepper()
  const isActive = value === activeValue
  const state: StepState = isActive ? "active" : completed ? "completed" : "upcoming"

  return (
    <StepperItemContext.Provider value={{ value, state, disabled }}>
      <div
        data-slot="stepper-item"
        data-state={state}
        data-orientation={orientation}
        data-disabled={disabled ? "" : undefined}
        className={cn(
          "group/stepper-item flex",
          orientation === "horizontal"
            ? "shrink-0 flex-col items-center"
            : "flex-row gap-4 items-start",
          className
        )}
        {...props}
      />
    </StepperItemContext.Provider>
  )
}

// ─── StepperTrigger ───────────────────────────────────────────────────────────

function StepperTrigger({
  className,
  children,
  ...props
}: React.ComponentProps<"button">) {
  const { onValueChange, orientation } = useStepper()
  const { value, state, disabled } = useStepperItem()

  return (
    <button
      type="button"
      data-slot="stepper-trigger"
      data-state={state}
      data-orientation={orientation}
      disabled={disabled}
      onClick={() => {
        if (!disabled) onValueChange(value)
      }}
      className={cn(
        "inline-flex shrink-0 items-center gap-3 rounded-md transition-opacity",
        "disabled:pointer-events-none disabled:opacity-50",
        "focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2",
        "hover:opacity-80",
        orientation === "horizontal" && "flex-col items-center",
        className
      )}
      {...props}
    >
      {/* Step indicator: check icon when completed, dot otherwise */}
      <span
        className={cn(
          "flex size-8 shrink-0 items-center justify-center rounded-full border-2 transition-colors",
          state === "active" &&
            "border-primary bg-primary text-primary-foreground",
          state === "completed" &&
            "border-primary bg-primary text-primary-foreground",
          state === "upcoming" &&
            "border-border bg-background text-muted-foreground"
        )}
      >
        {state === "completed" ? (
          <CheckIcon className="size-4" />
        ) : (
          <span
            className={cn(
              "size-2 rounded-full bg-current",
              state === "upcoming" && "opacity-40"
            )}
          />
        )}
      </span>

      {/* Title / description slot */}
      {children && (
        <span
          className={cn(
            "flex flex-col gap-0.5",
            orientation === "horizontal" && "items-center text-center"
          )}
        >
          {children}
        </span>
      )}
    </button>
  )
}

// ─── StepperTitle ─────────────────────────────────────────────────────────────

function StepperTitle({ className, ...props }: React.ComponentProps<"p">) {
  const { state } = useStepperItem()
  return (
    <p
      data-slot="stepper-title"
      data-state={state}
      className={cn(
        "text-sm font-semibold leading-none",
        state === "upcoming" && "text-muted-foreground",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperDescription ───────────────────────────────────────────────────────

function StepperDescription({
  className,
  ...props
}: React.ComponentProps<"p">) {
  return (
    <p
      data-slot="stepper-description"
      className={cn("text-xs text-muted-foreground", className)}
      {...props}
    />
  )
}

// ─── StepperSeparator ─────────────────────────────────────────────────────────

/**
 * Visual divider between steps.
 *
 * - In **horizontal** mode: place inside `<StepperList>` between two
 *   `<StepperItem>` elements. Renders as a horizontal line that flexes to fill
 *   the available space, vertically centred with the step indicator circles.
 * - In **vertical** mode: place directly inside `<Stepper>` between two
 *   `<StepperItem>` elements. Renders as a short vertical line aligned under
 *   the indicator circles.
 */
function StepperSeparator({
  className,
  ...props
}: React.ComponentProps<"div">) {
  const { orientation } = useStepper()
  return (
    <div
      role="none"
      data-slot="stepper-separator"
      data-orientation={orientation}
      className={cn(
        "shrink-0 bg-border transition-colors",
        // horizontal: flex-1 fills the gap; mt-4 centres on the 32 px circle
        orientation === "horizontal" ? "mt-4 h-px flex-1 min-w-8" : "ms-4 h-6 w-px",
        className
      )}
      {...props}
    />
  )
}

// ─── StepperContent ───────────────────────────────────────────────────────────

interface StepperContentProps extends React.ComponentProps<"div"> {
  /**
   * The step value this panel belongs to. Required when used outside of a
   * `<StepperItem>`; optional when used inside (inherits the item value).
   */
  value?: string
}

/**
 * Content panel that is shown only when its associated step is active.
 *
 * Can be used in two ways:
 * 1. **Outside** `<StepperItem>` – pass an explicit `value` prop matching the
 *    step's value (mirrors the `<TabsContent>` pattern).
 * 2. **Inside** `<StepperItem>` – omit `value`; the step value is inherited
 *    from the enclosing item context (convenient for vertical layouts).
 */
function StepperContent({
  value: valueProp,
  className,
  children,
  ...props
}: StepperContentProps) {
  const { value: activeValue, orientation } = useStepper()
  const itemContext = React.useContext(StepperItemContext)
  const stepValue = valueProp ?? itemContext?.value

  if (stepValue !== activeValue) return null

  return (
    <div
      data-slot="stepper-content"
      data-orientation={orientation}
      className={cn(
        orientation === "vertical" ? "pb-6 ps-12" : "mt-4",
        className
      )}
      {...props}
    >
      {children}
    </div>
  )
}

// ─── Exports ──────────────────────────────────────────────────────────────────

export {
  Stepper,
  StepperList,
  StepperItem,
  StepperTrigger,
  StepperTitle,
  StepperDescription,
  StepperSeparator,
  StepperContent,
  useStepper,
  useStepperItem,
}

