"use client"

import * as React from "react"

import { Button } from "@/registry/new-york-v4/ui/button"
import {
  Stepper,
  StepperContent,
  StepperDescription,
  StepperItem,
  StepperList,
  StepperSeparator,
  StepperTitle,
  StepperTrigger,
} from "@/registry/new-york-v4/ui/stepper"

const STEPS = [
  {
    value: "account",
    title: "Account",
    description: "Create your account",
    content:
      "Choose a unique username and a strong password. Your email address will be used for verification and account recovery.",
  },
  {
    value: "profile",
    title: "Profile",
    description: "Add your details",
    content:
      "Tell us a bit about yourself. You can add a display name, bio, and profile picture to personalise your experience.",
  },
  {
    value: "review",
    title: "Review",
    description: "Confirm and submit",
    content:
      "Everything looks good! Review your information above and click Finish to complete your account setup.",
  },
]

export default function StepperDemo() {
  const [current, setCurrent] = React.useState(STEPS[0].value)

  const currentIndex = STEPS.findIndex((s) => s.value === current)

  function handleNext() {
    if (currentIndex < STEPS.length - 1) {
      setCurrent(STEPS[currentIndex + 1].value)
    }
  }

  function handlePrev() {
    if (currentIndex > 0) {
      setCurrent(STEPS[currentIndex - 1].value)
    }
  }

  return (
    <div className="w-full max-w-lg space-y-8 px-2">
      {/* ── Horizontal stepper ── */}
      <Stepper value={current} onValueChange={setCurrent}>
        <StepperList>
          {STEPS.map((step, index) => (
            <React.Fragment key={step.value}>
              <StepperItem
                value={step.value}
                completed={index < currentIndex}
              >
                <StepperTrigger>
                  <StepperTitle>{step.title}</StepperTitle>
                  <StepperDescription>{step.description}</StepperDescription>
                </StepperTrigger>
              </StepperItem>
              {index < STEPS.length - 1 && <StepperSeparator />}
            </React.Fragment>
          ))}
        </StepperList>

        {STEPS.map((step) => (
          <StepperContent key={step.value} value={step.value}>
            <div className="rounded-lg border bg-card p-4 text-sm text-muted-foreground shadow-sm">
              {step.content}
            </div>
          </StepperContent>
        ))}
      </Stepper>

      {/* ── Navigation ── */}
      <div className="flex items-center justify-between">
        <Button
          variant="outline"
          size="sm"
          onClick={handlePrev}
          disabled={currentIndex === 0}
        >
          Previous
        </Button>
        <span className="text-xs text-muted-foreground">
          Step {currentIndex + 1} of {STEPS.length}
        </span>
        <Button
          size="sm"
          onClick={handleNext}
          disabled={currentIndex === STEPS.length - 1}
        >
          {currentIndex === STEPS.length - 1 ? "Finish" : "Next"}
        </Button>
      </div>

      {/* ── Vertical stepper ── */}
      <Stepper
        orientation="vertical"
        value={current}
        onValueChange={setCurrent}
      >
        {STEPS.map((step, index) => (
          <React.Fragment key={step.value}>
            <StepperItem
              value={step.value}
              completed={index < currentIndex}
            >
              <StepperTrigger>
                <StepperTitle>{step.title}</StepperTitle>
                <StepperDescription>{step.description}</StepperDescription>
              </StepperTrigger>
              <StepperContent>
                <div className="rounded-lg border bg-card p-4 text-sm text-muted-foreground shadow-sm">
                  {step.content}
                </div>
              </StepperContent>
            </StepperItem>
            {index < STEPS.length - 1 && <StepperSeparator />}
          </React.Fragment>
        ))}
      </Stepper>
    </div>
  )
}

